import { useParams } from "react-router-dom";
import { useState } from "react";

export default function IncidentDetail() {
  const { id } = useParams();

  const [form, setForm] = useState({
    start: "",
    end: "",
    rootCause: "",
    fix: "",
    prevention: ""
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      await fetch(`http://localhost:8000/close/${id}`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(form)
      });

      alert("Closed!");
    } catch {
      alert("Error!");
    }
  };

  return (
    <div>
      <h2>Incident {id}</h2>

      <form onSubmit={handleSubmit}>
        <input type="datetime-local" name="start" onChange={handleChange} />
        <input type="datetime-local" name="end" onChange={handleChange} />
        <input name="rootCause" placeholder="Root Cause" onChange={handleChange} />
        <input name="fix" placeholder="Fix" onChange={handleChange} />
        <input name="prevention" placeholder="Prevention" onChange={handleChange} />

        <button type="submit">Close</button>
      </form>
    </div>
  );
}
